[
    {"type": "bullet", "label": "5.1", "text": "This Agreement shall commence on the Effective Date and shall remain in full force and effect for a period of five (5) years, unless earlier terminated."},
    {"type": "bullet", "label": "5.2", "text": "Either Party may terminate this Agreement by providing thirty (30) days\u2019 prior written notice."},
    {"type": "bullet", "label": "5.3", "text": "The obligations of confidentiality shall survive for a period of five (5) years following expiration or termination. With respect to Trade Secrets, the obligations shall survive for as long as such information remains a Trade Secret."},
    {"type": "bullet", "label": "5.4", "text": "Upon termination, the Receiving Party shall immediately cease all use of the Confidential Information and comply with the return obligations set forth in Section 6."}
]

[
    {"type": "bullet", "label": "6.1", "text": "Upon expiration, termination, or written request, the Receiving Party shall promptly return or destroy all Materials containing Confidential Information and provide written certification of destruction within fifteen (15) business days."},
    {"type": "bullet", "label": "6.2", "text": "For electronically stored Confidential Information, the Receiving Party shall employ secure deletion methods (multi-pass overwrite, degaussing, or physical destruction of storage media)."},
    {"type": "bullet", "label": "6.3", "text": "The Receiving Party may retain one archival copy solely for compliance with applicable law, provided it remains subject to all confidentiality obligations."}
]

[
    {"type": "callout", "text": "The Parties acknowledge that any breach may cause irreparable injury for which monetary damages would be inadequate. The Disclosing Party shall be entitled to seek immediate injunctive relief without the necessity of proving actual damages or posting a bond."},
    {"type": "bullet", "label": "7.1", "text": "The rights and remedies are cumulative and in addition to any other rights available at law or in equity, including claims for damages, an accounting of profits, and recovery of attorneys\u2019 fees."},
    {"type": "bullet", "label": "7.2", "text": "The Receiving Party shall indemnify and hold harmless the Disclosing Party from all claims, damages, losses, and expenses arising from any breach of this Agreement."}
]

[
    {"type": "paragraph", "text": "During the term and for two (2) years following termination, the Receiving Party shall not use Confidential Information to directly or indirectly solicit, recruit, or hire any employee, contractor, or key personnel of the Company, or to solicit or divert any client, customer, supplier, or business partner of the Company."}
]

[
    {"type": "bullet", "label": "9.1", "text": "Nothing in this Agreement grants the Receiving Party any right, title, or interest in the Confidential Information or any intellectual property of the Disclosing Party."},
    {"type": "bullet", "label": "9.2", "text": "Any inventions or work product created using the Company\u2019s Confidential Information shall be governed by the Consulting Agreement and shall be the sole property of the Company."},
    {"type": "bullet", "label": "9.3", "text": "ALL CONFIDENTIAL INFORMATION IS PROVIDED \u201cAS IS.\u201d NEITHER PARTY MAKES ANY WARRANTY WITH RESPECT TO THE ACCURACY, COMPLETENESS, OR FITNESS FOR A PARTICULAR PURPOSE OF ANY CONFIDENTIAL INFORMATION."}
]

[
    {"type": "bullet", "label": "10.1", "text": "This Agreement shall be governed by the laws of the State of Delaware, without regard to conflict of laws principles."},
    {"type": "bullet", "label": "10.2", "text": "The Parties submit to the exclusive jurisdiction of the courts of the State of Delaware. Each Party waives any objection to venue."},
    {"type": "bullet", "label": "10.3", "text": "In any action to enforce this Agreement, the prevailing Party shall be entitled to recover reasonable attorneys\u2019 fees and costs."}
]

[
    {"type": "paragraph", "text": "This Agreement, together with the Consulting Agreement dated {effective_date}, constitutes the entire agreement between the Parties with respect to the subject matter hereof. In the event of any conflict regarding Confidential Information, the more restrictive provision shall prevail."}
]
